{"cmd":"python3 - <<'PY'
import json, re
from pathlib import Path
s=Path('/tmp/clientauthconfig_discovery_raw.txt').read_text()
# strip HTTP line
j=json.loads(s.rsplit('\nHTTP ',1)[0])
Path('/tmp/clientauthconfig_discovery.json').write_text(json.dumps(j, indent=2))

def walk_resources(resources, prefix=''):
    for rname, r in (resources or {}).items():
        p=f'{prefix}.{rname}' if prefix else rname
        for mname, m in (r.get('methods') or {}).items():
            if 'client' in p.lower() or 'client' in mname.lower() or 'Client' in json.dumps(m)[:500]:
                print('\nMETHOD', p+'.'+mname)
                for k in ['httpMethod','path','flatPath','id','request','response','parameters']:
                    if k in m:
                        print(k, json.dumps(m[k], indent=2)[:1500])
        walk_resources(r.get('resources'), p)
walk_resources(j.get('resources'))
print('schemas matching masks/client:')
for name, schema in j['schemas'].items():
    if any(x in name.lower() for x in ['client','redirect','javascript','origin','webinfo','mask']):
        if name in ['Client','ClientMask','WebInfoMask','WebClientInfo','ClientUpdateRequest'] or 'Web' in name or 'Client' in name or 'Redirect' in json.dumps(schema):
            print('\nSCHEMA', name, json.dumps(schema, indent=2)[:2500])
PY","workdir":"/worksp/monitor","yield_time_ms":10000,"max_output_tokens":30000}

